import{_ as e,o,c as t,e as n}from"./app-365be48d.js";const i={},r=n('<h1 id="soups-software-of-unknown-provenance" tabindex="-1"><a class="header-anchor" href="#soups-software-of-unknown-provenance" aria-hidden="true">#</a> SOUPS - Software of Unknown Provenance</h1><p>Software of unknown provenance (SOUPS) is a software item that is already developed, generally available and not developed for the purpose of being incorporated into the bioinformatic workflow, or a software item for which adequate software documentation is not available. A procedure should be documented about how and where SOUPS are registered.</p><p>For each SOUP the following items should be registered:</p><ul><li>Name: Name of SOUP.</li><li>Reference: Link (URL) to soup (source code / publication).</li><li>Intended purpose: Description of the original purpose of the SOUP.</li><li>Used according to the intended purpose: yes/no, if no, document for which purpose the SOUP is used.</li><li>Validation required: yes/no, often this is part of the validation of the (workflow) release itself. When using the SOUP outside of its intended purpose you need a proper validation to show that it works.</li><li>Version controlled: yes/no, is the SOUP developed under version control or not.</li><li></li></ul>',4),a=[r];function s(l,d){return o(),t("div",null,a)}const p=e(i,[["render",s],["__file","soups.html.vue"]]);export{p as default};
